\tkvfree(kbuf);\n\n\treturn written;\n}\n\nstatic const struct file_operations proc_zram_block_state_op = {\n\t.open = simple_open,\n\t.read = read_block_state,\n\t.llseek = default_llseek,\n};\n\nstatic void zram_debugfs_register(struct zram *zram)\n{\n\tif (!zram_debugfs_root)\n\t\treturn;\n\n\tzram->debugfs_dir = debugfs_create_dir(zram->disk->disk_name,\n\t\t\t\t\t\tzram_debugfs_root);\n\tdebugfs_create_file(\"block_state\", 0400, zram->debugfs_dir,\n\t\t\t\tzram, &proc_zram_block_state_op);\n}\n\nstatic void zram_debugfs_unregister(struct zram *zram)\n{\n\tdebugfs_remove_recursive(zram->debugfs_dir);\n}\n#else\nstatic void zram_debugfs_create(void) {};\nstatic void zram_debugfs_destroy(void) {};\nstatic void zram_debugfs_register(struct zram *zram) {};\nstatic void zram_debugfs_unregister(struct zram *zram) {};\n#endif\n\nstatic void comp_algorithm_set(struct zram *zram, u32 prio, const char *alg)\n{\n\t/* Do not free statically defined compression algorithms */\n\tif (zram->comp_algs[prio] != default_compressor)\n\t\tkfree(zram->comp_algs[prio]);\n\n\tzram->comp_algs[prio] = alg;\n}\n\nstatic int __comp_algorithm_store(struct zram *zram, u32 prio, const char *buf)\n{\n\tchar *compressor;\n\tsize_t sz;\n\n\tsz = strlen(buf);\n\tif (sz >= ZRAM_MAX_ALGO_NAME_SZ)\n\t\treturn -E2BIG;\n\n\tcompressor = kstrdup(buf, GFP_KERNEL);\n\tif (!compressor)\n\t\treturn -ENOMEM;\n\n\t/* ignore trailing newline */\n\tif (sz > 0 && compressor[sz - 1] == '\\n')\n\t\tcompressor[sz - 1] = 0x00;\n\n\tif (!zcomp_available_algorithm(compressor)) {\n\t\tkfree(compressor);\n\t\treturn -EINVAL;\n\t}\n\n\tguard(rwsem_write)(&zram->dev_lock);\n\tif (init_done(zram)) {\n\t\tkfree(compressor);\n\t\tpr_info(\"Can't change algorithm for initialized device\\n\");\n\t\treturn -EBUSY;\n\t}\n\n\tcomp_algorithm_set(zram, prio, compressor);\n\treturn 0;\n}\n\nstatic void comp_params_reset(struct zram *zram, u32 prio)\n{\n\tstruct zcomp_params *params = &zram->params[prio];\n\n\tvfree(params->dict);\n\tparams->level = ZCOMP_PARAM_NOT_SET;\n\tparams->deflate.winbits = ZCOMP_PARAM_NOT_SET;\n\tparams->dict_sz = 0;\n\tparams->dict = NULL;\n}\n\nstatic int comp_params_store(struct zram *zram, u32 prio, s32 level,\n\t\t\t     const char *dict_path,\n\t\t\t     struct deflate_params *deflate_params)\n{\n\tssize_t sz = 0;\n\n\tcomp_params_reset(zram, prio);\n\n\tif (dict_path) {\n\t\tsz = kernel_read_file_from_path(dict_path, 0,\n\t\t\t\t\t\t&zram->params[prio].dict,\n\t\t\t\t\t\tINT_MAX,\n\t\t\t\t\t\tNULL,\n\t\t\t\t\t\tREADING_POLICY);\n\t\tif (sz < 0)\n\t\t\treturn -EINVAL;\n\t}\n\n\tzram->params[prio].dict_sz = sz;\n\tzram->params[prio].level = level;\n\tzram->params[prio].deflate.winbits = deflate_params->winbits;\n\treturn 0;\n}\n\nstatic ssize_t algorithm_params_store(struct device *dev,\n\t\t\t\t      struct device_attribute *attr,\n\t\t\t\t      const char *buf,\n\t\t\t\t      size_t len)\n{\n\ts32 prio = ZRAM_PRIMARY_COMP, level = ZCOMP_PARAM_NOT_SET;\n\tchar *args, *param, *val, *algo = NULL, *dict_path = NULL;\n\tstruct deflate_params deflate_params;\n\tstruct zram *zram = dev_to_zram(dev);\n\tint ret;\n\n\tdeflate_params.winbits = ZCOMP_PARAM_NOT_SET;\n\n\targs = skip_spaces(buf);\n\twhile (*args) {\n\t\targs = next_arg(args, &param, &val);\n\n\t\tif (!val || !*val)\n\t\t\treturn -EINVAL;\n\n\t\tif (!strcmp(param, \"priority\")) {\n\t\t\tret = kstrtoint(val, 10, &prio);\n\t\t\tif (ret)\n\t\t\t\treturn ret;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (!strcmp(param, \"level\")) {\n\t\t\tret = kstrtoint(val, 10, &level);\n\t\t\tif (ret)\n\t\t\t\treturn ret;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (!strcmp(param, \"algo\")) {\n\t\t\talgo = val;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (!strcmp(param, \"dict\")) {\n\t\t\tdict_path = val;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (!strcmp(param, \"deflate.winbits\")) {\n\t\t\tret = kstrtoint(val, 10, &deflate_params.winbits);\n\t\t\tif (ret)\n\t\t\t\treturn ret;\n\t\t\tcontinue;\n\t\t}\n\t}\n\n\t/* Lookup priority by algorithm name */\n\tif (algo) {\n\t\ts32 p;\n\n\t\tprio = -EINVAL;\n\t\tfor (p = ZRAM_PRIMARY_COMP; p < ZRAM_MAX_COMPS; p++) {\n\t\t\tif (!zram->comp_algs[p])\n\t\t\t\tcontinue;\n\n\t\t\tif (!strcmp(zram->comp_algs[p], algo)) {\n\t\t\t\tprio = p;\n\t\t\t\tbreak;\n\t\t\t}\n\t\t}\n\t}\n\n\tif (prio < ZRAM_PRIMARY_COMP || prio >= ZRAM_MAX_COMPS)\n\t\treturn -EINVAL;\n\n\tret = comp_params_store(zram, prio, level, dict_path, &deflate_params);\n\treturn ret ? ret : len;\n}\n\nstatic ssize_t comp_algorithm_show(struct device *dev,\n\t\t\t\t   struct device_attribute *attr,\n\t\t\t\t   char *buf)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tssize_t sz;\n\n\tguard(rwsem_read)(&zram->dev_lock);\n\tsz = zcomp_available_show(zram->comp_algs[ZRAM_PRIMARY_COMP], buf, 0);\n\treturn sz;\n}\n\nstatic ssize_t comp_algorithm_store(struct device *dev,\n\t\t\t\t    struct device_attribute *attr,\n\t\t\t\t    const char *buf,\n\t\t\t\t    size_t len)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tint ret;\n\n\tret = __comp_algorithm_store(zram, ZRAM_PRIMARY_COMP, buf);\n\treturn ret ? ret : len;\n}\n\n#ifdef CONFIG_ZRAM_MULTI_COMP\nstatic ssize_t recomp_algorithm_show(struct device *dev,\n\t\t\t\t     struct device_attribute *attr,\n\t\t\t\t     char *buf)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tssize_t sz = 0;\n\tu32 prio;\n\n\tguard(rwsem_read)(&zram->dev_lock);\n\tfor (prio = ZRAM_SECONDARY_COMP; prio < ZRAM_MAX_COMPS; prio++) {\n\t\tif (!zram->comp_algs[prio])\n\t\t\tcontinue;\n\n\t\tsz += sysfs_emit_at(buf, sz, \"#%d: \", prio);\n\t\tsz += zcomp_available_show(zram->comp_algs[prio], buf, sz);\n\t}\n\treturn sz;\n}\n\nstatic ssize_t recomp_algorithm_store(struct device *dev,\n\t\t\t\t      struct device_attribute *attr,\n\t\t\t\t      const char *buf,\n\t\t\t\t      size_t len)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tint prio = ZRAM_SECONDARY_COMP;\n\tchar *args, *param, *val;\n\tchar *alg = NULL;\n\tint ret;\n\n\targs = skip_spaces(buf);\n\twhile (*args) {\n\t\targs = next_arg(args, &param, &val);\n\n\t\tif (!val || !*val)\n\t\t\treturn -EINVAL;\n\n\t\tif (!strcmp(param, \"algo\")) {\n\t\t\talg = val;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (!strcmp(param, \"priority\")) {\n\t\t\tret = kstrtoint(val, 10, &prio);\n\t\t\tif (ret)\n\t\t\t\treturn ret;\n\t\t\tcontinue;\n\t\t}\n\t}\n\n\tif (!alg)\n\t\treturn -EINVAL;\n\n\tif (prio < ZRAM_SECONDARY_COMP || prio >= ZRAM_MAX_COMPS)\n\t\treturn -EINVAL;\n\n\tret = __comp_algorithm_store(zram, prio, alg);\n\treturn ret ? ret : len;\n}\n#endif\n\nstatic ssize_t compact_store(struct device *dev, struct device_attribute *attr,\n\t\t\t     const char *buf, size_t len)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\n\tguard(rwsem_read)(&zram->dev_lock);\n\tif (!init_done(zram))\n\t\treturn -EINVAL;\n\n\tzs_compact(zram->mem_pool);\n\n\treturn len;\n}\n\nstatic ssize_t io_stat_show(struct device *dev, struct device_attribute *attr,\n\t\t\t    char *buf)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tssize_t ret;\n\n\tguard(rwsem_read)(&zram->dev_lock);\n\tret = sysfs_emit(buf,\n\t\t\t\"%8llu %8llu 0 %8llu\\n\",\n\t\t\t(u64)atomic64_read(&zram->stats.failed_reads),\n\t\t\t(u64)atomic64_read(&zram->stats.failed_writes),\n\t\t\t(u64)atomic64_read(&zram->stats.notify_free));\n\n\treturn ret;\n}\n\nstatic ssize_t mm_stat_show(struct device *dev, struct device_attribute *attr,\n\t\t\t    char *buf)\n{\n\tstruct zram *zram = dev_to_zram(dev);\n\tstruct zs_pool_stats pool_stats;\n\tu64 orig_size, mem_used = 0;\n\tlong max_used;\n\tssize_t ret;\n\n\tmemset(&pool_stats, 0x00, sizeof(struct zs_pool_stats));\n\n\tguard(rwsem_read)(&zram->dev_lock);\n\tif (init_done(zram)) {\n\t\tmem_used = zs_get_total_pages(zram->mem_pool);\n\t\tzs_pool_stats(zram->mem_pool, &pool_stats);\n\t}\n\n\torig_size = atomic64_read(&zram->stats.pages_stored);\n\tmax_used = atomic_long_read(&zram->stats.max_used_pages);\n\n\tret = sysfs_emit(buf,\n\t\t\t\"%8llu %8llu %8llu %8lu %8ld %8llu %8lu %8llu %8llu\\n\",\n\t\t\torig_size << PAGE_SHIFT,\n\n... [Diff truncated. Dropped 997 lines] ...\n\n\nout_free_comps:\n\tzram_destroy_comps(zram);\n\tzram_meta_free(zram, disksize);\n\treturn err;\n}\n\nstatic ssize_t reset_store(struct device *dev,\n\t\tstruct device_attribute *attr, const char *buf, size_t len)\n{\n\tint ret;\n\tunsigned short do_reset;\n\tstruct zram *zram;\n\tstruct gendisk *disk;\n\n\tret = kstrtou16(buf, 10, &do_reset);\n\tif (ret)\n\t\treturn ret;\n\n\tif (!do_reset)\n\t\treturn -EINVAL;\n\n\tzram = dev_to_zram(dev);\n\tdisk = zram->disk;\n\n\tmutex_lock(&disk->open_mutex);\n\t/* Do not reset an active device or claimed device */\n\tif (disk_openers(disk) || zram->claim) {\n\t\tmutex_unlock(&disk->open_mutex);\n\t\treturn -EBUSY;\n\t}\n\n\t/* From now on, anyone can't open /dev/zram[0-9] */\n\tzram->claim = true;\n\tmutex_unlock(&disk->open_mutex);\n\n\t/* Make sure all the pending I/O are finished */\n\tsync_blockdev(disk->part0);\n\tzram_reset_device(zram);\n\n\tmutex_lock(&disk->open_mutex);\n\tzram->claim = false;\n\tmutex_unlock(&disk->open_mutex);\n\n\treturn len;\n}\n\nstatic int zram_open(struct gendisk *disk, blk_mode_t mode)\n{\n\tstruct zram *zram = disk->private_data;\n\n\tWARN_ON(!mutex_is_locked(&disk->open_mutex));\n\n\t/* zram was claimed to reset so open request fails */\n\tif (zram->claim)\n\t\treturn -EBUSY;\n\treturn 0;\n}\n\nstatic const struct block_device_operations zram_devops = {\n\t.open = zram_open,\n\t.submit_bio = zram_submit_bio,\n\t.swap_slot_free_notify = zram_slot_free_notify,\n\t.owner = THIS_MODULE\n};\n\nstatic DEVICE_ATTR_RO(io_stat);\nstatic DEVICE_ATTR_RO(mm_stat);\nstatic DEVICE_ATTR_RO(debug_stat);\nstatic DEVICE_ATTR_WO(compact);\nstatic DEVICE_ATTR_RW(disksize);\nstatic DEVICE_ATTR_RO(initstate);\nstatic DEVICE_ATTR_WO(reset);\nstatic DEVICE_ATTR_WO(mem_limit);\nstatic DEVICE_ATTR_WO(mem_used_max);\nstatic DEVICE_ATTR_WO(idle);\nstatic DEVICE_ATTR_RW(comp_algorithm);\n#ifdef CONFIG_ZRAM_WRITEBACK\nstatic DEVICE_ATTR_RO(bd_stat);\nstatic DEVICE_ATTR_RW(backing_dev);\nstatic DEVICE_ATTR_WO(writeback);\nstatic DEVICE_ATTR_RW(writeback_limit);\nstatic DEVICE_ATTR_RW(writeback_limit_enable);\nstatic DEVICE_ATTR_RW(writeback_batch_size);\nstatic DEVICE_ATTR_RW(compressed_writeback);\n#endif\n#ifdef CONFIG_ZRAM_MULTI_COMP\nstatic DEVICE_ATTR_RW(recomp_algorithm);\nstatic DEVICE_ATTR_WO(recompress);\n#endif\nstatic DEVICE_ATTR_WO(algorithm_params);\n\nstatic struct attribute *zram_disk_attrs[] = {\n\t&dev_attr_disksize.attr,\n\t&dev_attr_initstate.attr,\n\t&dev_attr_reset.attr,\n\t&dev_attr_compact.attr,\n\t&dev_attr_mem_limit.attr,\n\t&dev_attr_mem_used_max.attr,\n\t&dev_attr_idle.attr,\n\t&dev_attr_comp_algorithm.attr,\n#ifdef CONFIG_ZRAM_WRITEBACK\n\t&dev_attr_bd_stat.attr,\n\t&dev_attr_backing_dev.attr,\n\t&dev_attr_writeback.attr,\n\t&dev_attr_writeback_limit.attr,\n\t&dev_attr_writeback_limit_enable.attr,\n\t&dev_attr_writeback_batch_size.attr,\n\t&dev_attr_compressed_writeback.attr,\n#endif\n\t&dev_attr_io_stat.attr,\n\t&dev_attr_mm_stat.attr,\n\t&dev_attr_debug_stat.attr,\n#ifdef CONFIG_ZRAM_MULTI_COMP\n\t&dev_attr_recomp_algorithm.attr,\n\t&dev_attr_recompress.attr,\n#endif\n\t&dev_attr_algorithm_params.attr,\n\tNULL,\n};\n\nATTRIBUTE_GROUPS(zram_disk);\n\n/*\n * Allocate and initialize new zram device. the function returns\n * '>= 0' device_id upon success, and negative value otherwise.\n */\nstatic int zram_add(void)\n{\n\tstruct queue_limits lim = {\n\t\t.logical_block_size\t\t= ZRAM_LOGICAL_BLOCK_SIZE,\n\t\t/*\n\t\t * To ensure that we always get PAGE_SIZE aligned and\n\t\t * n*PAGE_SIZED sized I/O requests.\n\t\t */\n\t\t.physical_block_size\t\t= PAGE_SIZE,\n\t\t.io_min\t\t\t\t= PAGE_SIZE,\n\t\t.io_opt\t\t\t\t= PAGE_SIZE,\n\t\t.max_hw_discard_sectors\t\t= UINT_MAX,\n\t\t/*\n\t\t * zram_bio_discard() will clear all logical blocks if logical\n\t\t * block size is identical with physical block size(PAGE_SIZE).\n\t\t * But if it is different, we will skip discarding some parts of\n\t\t * logical blocks in the part of the re